transform_js:
const subjectMap = {};
const metricsObj = {};
rawData.rows.forEach(r => {
  if (!subjectMap[r.subject]) subjectMap[r.subject] = {};
  subjectMap[r.subject][r.metric] = r.score;
  metricsObj[r.metric] = true;
});
const indicator = Object.keys(metricsObj).map(m => ({ name: m, max: 100 }));
const seriesData = Object.keys(subjectMap).map(subj => {
   return {
       name: subj,
       value: Object.keys(metricsObj).map(m => subjectMap[subj][m] || 0)
   };
});
transformedData = { indicator, seriesData };

echarts_js:
option = {
  title: {
    text: 'Product Comparison (Radar)',
    left: 'center'
  },
  tooltip: {
    trigger: 'item'
  },
  legend: {
    bottom: '5%',
    data: transformedData.seriesData.map(d => d.name)
  },
  radar: {
    indicator: transformedData.indicator,
    shape: 'circle',
    splitNumber: 5,
    axisName: {
      color: '#fff',
      backgroundColor: '#666',
      borderRadius: 3,
      padding: [3, 5]
    }
  },
  series: [
    {
      name: 'Product Comparison',
      type: 'radar',
      data: transformedData.seriesData,
      areaStyle: {
        opacity: 0.2
      },
      lineStyle: {
        width: 3
      },
      symbolSize: 8
    }
  ]
};
